function calculate(inputs) {
    const initialSystemCost = inputs.initialSystemCost;
    const analysisPeriod = inputs.analysisPeriod;
    const currentAnnualConsumption = inputs.currentAnnualConsumption;
    const systemAnnualProduction = inputs.systemAnnualProduction;
    const currentElectricityRate = inputs.currentElectricityRate;
    const electricityInflationRate = inputs.electricityInflationRate / 100;
    const systemDegradationRate = inputs.systemDegradationRate / 100;
    const annualMaintenanceCostPercent = inputs.annualMaintenanceCost / 100;
    const taxCreditRate = (inputs.taxCreditRate || 0) / 100;
    const rebateAmount = inputs.rebateAmount || 0;
    const netMeteringExportRate = inputs.netMeteringExportRate / 100;
    const discountRate = inputs.discountRate / 100;
    const gridCarbonIntensity = inputs.gridCarbonIntensity;

    // Edge cases and caps
    if (analysisPeriod <= 0) return { error: 'Analysis period must be positive.' };
    if (currentAnnualConsumption <= 0) return { error: 'Current annual consumption must be positive.' };
    if (currentElectricityRate <= 0) return { error: 'Current electricity rate must be positive.' };

    const netInitialInvestment = initialSystemCost * (1 - taxCreditRate) - rebateAmount;

    let cumulativeEnergySavings = 0;
    let cumulativeCarbonReduction = 0;
    let cumulativeCashFlow = -netInitialInvestment;
    let npv = -netInitialInvestment;
    let paybackPeriod = null;

    let currentYearElectricityRate = currentElectricityRate;
    let currentYearSystemProduction = systemAnnualProduction;

    for (let year = 1; year <= analysisPeriod; year++) {
        // Calculate costs and savings for the year
        const costWithoutSolar = currentAnnualConsumption * currentYearElectricityRate;
        const annualMaintenanceCost = initialSystemCost * annualMaintenanceCostPercent;

        // Determine self-consumption vs. export
        const selfConsumption = Math.min(currentYearSystemProduction, currentAnnualConsumption);
        const energyExported = Math.max(0, currentYearSystemProduction - currentAnnualConsumption);

        const savingsFromSelfConsumption = selfConsumption * currentYearElectricityRate;
        const incomeFromExport = energyExported * currentYearElectricityRate * netMeteringExportRate;

        const annualSavings = savingsFromSelfConsumption + incomeFromExport - annualMaintenanceCost;

        cumulativeEnergySavings += annualSavings;

        // Carbon reduction
        const yearCarbonReduction = (currentYearSystemProduction / 1000) * gridCarbonIntensity; // MWh to kWh
        cumulativeCarbonReduction += yearCarbonReduction;

        // Cash flow and NPV
        const cashFlowThisYear = annualSavings;
        cumulativeCashFlow += cashFlowThisYear;
        npv += cashFlowThisYear / Math.pow(1 + discountRate, year);

        // Payback period calculation
        if (paybackPeriod === null && cumulativeCashFlow >= 0) {
            paybackPeriod = year - 1 + (- (cumulativeCashFlow - cashFlowThisYear)) / cashFlowThisYear;
        }

        // Update rates for next year
        currentYearElectricityRate *= (1 + electricityInflationRate);
        currentYearSystemProduction *= (1 - systemDegradationRate);
    }

    // Handle case where payback doesn't occur within analysis period
    if (paybackPeriod === null && cumulativeCashFlow < 0) {
        paybackPeriod = Infinity; // Indicates no payback within the analysis period
    }

    // Annualized ROI
    // For a project with initial investment C0 and NPV over N years, ROI can be estimated.
    // A simpler approach for annualized ROI in absence of explicit profit: (Total savings - Initial outlay) / Initial outlay / Analysis Period
    let annualizedROI = ((cumulativeEnergySavings - (initialSystemCost - netInitialInvestment)) / netInitialInvestment / analysisPeriod) * 100; // Simplified for this context
    if (netInitialInvestment <= 0) annualizedROI = 0; // Avoid division by zero

    return {
        totalInitialOutlay: netInitialInvestment,
        lifetimeEnergySavings: cumulativeEnergySavings,
        netPresentValue: npv,
        paybackPeriod: paybackPeriod,
        lifetimeCO2Reduction: cumulativeCarbonReduction,
        annualizedROI: annualizedROI
    };
}
